const assert=chai.assert;describe("Practice Assignment 10",(function(){describe("Question 1",(function(){it("getTheTable should exist.",(function(){assert.exists(getTheTable)})),it("getTheTable should be a function.",(function(){assert.isFunction(getTheTable)})),it("getTheTable should return the correct data.",(function(){const result=getTheTable();assert.strictEqual(result.id,"myTable")}))})),describe("Question 2",(function(){it("getAllParagraphs should exist.",(function(){assert.exists(getAllParagraphs)})),it("getAllParagraphs should be a function.",(function(){assert.isFunction(getAllParagraphs)})),it("getAllParagraphs should return a NodeList with the correct length.",(function(){const result=getAllParagraphs();assert.strictEqual(result.length,4)})),it("getAllParagraphs should return a NodeList with the correct data.",(function(){const result=getAllParagraphs()[2].textContent;assert.strictEqual(result.length,149)}))})),describe("Question 3",(function(){it("makeItalic should exist.",(function(){assert.exists(makeItalic)})),it("makeItalic should be a function.",(function(){assert.isFunction(makeItalic)})),it("makeItalic should return a NodeList with the correct length.",(function(){const result=makeItalic();assert.strictEqual(result.length,2)})),it("makeItalic should return a NodeList with the correct data.",(function(){let result=makeItalic()[1].textContent;assert.strictEqual(result.length,149),result=makeItalic()[0].textContent,assert.strictEqual(result.length,129)})),it("makeItalic should change the paragraphs with the class 'even' to italics.",(function(){const evens=document.querySelectorAll("p.even");evens.forEach(p=>{assert.strictEqual(p.style.fontStyle,"italic")})}))})),describe("Question 4",(function(){it("createBorders should exist.",(function(){assert.exists(createBorders)})),it("createBorders should be a function.",(function(){assert.isFunction(createBorders)})),it("createBorders should return the table element.",(function(){const result=createBorders();assert.strictEqual(result.id,"myTable")})),it("createBorders should add a border to the cells inside the table.",(function(){const result=createBorders(),cells=document.querySelectorAll("#myTable td");cells.forEach(cell=>{assert.strictEqual(cell.style.border,"2px solid rgb(0, 0, 0)")})})),it("createBorders should not add a border to the table rows or table.",(function(){const result=createBorders(),myTable=document.getElementById("myTable");assert.strictEqual(myTable.style.border,"");const rows=myTable.getElementsByTagName("tr");rows.forEach(row=>{assert.strictEqual(row.style.border,"")})}))})),describe("Question 5",(function(){it("getTheListItem should exist.",(function(){assert.exists(getTheListItem)})),it("getTheListItem should be a function.",(function(){assert.isFunction(getTheListItem)})),it("getTheListItem should return text content.",(function(){const result=getTheListItem(2,3);assert.isString(result)})),it("getTheListItem should return accurate data.",(function(){let result=getTheListItem(2,3);assert.strictEqual(result,"Python"),result=getTheListItem(1,2),assert.strictEqual(result,"HTML")}))})),describe("Question 6",(function(){it("changeBgColor should exist.",(function(){assert.exists(changeBgColor)})),it("changeBgColor should be a function.",(function(){assert.isFunction(changeBgColor)})),it("changeBgColor should return the element with the id 'myPage'.",(function(){const result=changeBgColor();assert.strictEqual(result.id,"myPage")})),it("changeBgColor should change the background color of the 'myPage' element.",(function(){let result=changeBgColor("blue");assert.strictEqual(result.style.backgroundColor,"blue"),result=changeBgColor("lightgray"),assert.strictEqual(result.style.backgroundColor,"lightgray"),result=changeBgColor("#fff"),assert.strictEqual(result.style.backgroundColor,"rgb(255, 255, 255)")}))}))}));